import tensorflow as tfimport numpy as npimport matplotlib.pyplot as plt# 使用numpy生成200个随机点x_data = np.linspace(-0.5, 0.5, 200)[:, np.newaxis]noise = np.random.normal(0, 0.02, x_data.shape)y_data = np.square(x_data) + noiseplt.scatter(x_data, y_data)plt.show()# 定义模型class Model(object):    def __init__(self):        self.w1 = tf.Variable(tf.random.normal([1, 10]))        self.b1 = tf.Variable(tf.zeros([1, 10]))        self.w2 = tf.Variable(tf.random.normal([10, 1]))        self.b2 = tf.Variable(0.1)    def __call__(self, inputs):        output = inputs @ self.w1 + self.b1        output = tf.nn.tanh(output)        output = output @ self.w2 + self.b2        output = tf.nn.tanh(output)        return output# 定义损失函数def compute_loss(y_true, y_pred):    return tf.reduce_mean(tf.square(y_true-y_pred))# 绘制数据 蓝色表示原始数据  红色表示预测数据plt.figure("非线性回归")def plot(predict_y, i, loss):    # 绘制散点图    plt.cla()    plt.scatter(x_data, y_data)    plt.plot(x_data, predict_y, 'r', lw=5)    plt.title("epoch = %2d, loss = %s" % (i, str(loss)))    plt.ion()    plt.pause(0.01)    plt.ioff()learn_rate = 0.2   # 学习率epoch = 1000       # 训练轮数model = Model()    # 定义模型loss_buf = []      # 存储每一个批次的损失值for i in range(0, epoch + 1):    with tf.GradientTape() as tape:        PRED_train = model(x_data)        Loss_train = compute_loss(y_data, PRED_train)    grad = tape.gradient(Loss_train, [model.w1, model.b1, model.w2, model.b2])    model.w1.assign_sub(learn_rate * grad[0])    model.b1.assign_sub(learn_rate * grad[1])    model.w2.assign_sub(learn_rate * grad[2])    model.b2.assign_sub(learn_rate * grad[3])    if i % 20 == 0:        print("epoch:%i, Train Loss:%f" % (i, Loss_train.numpy()))        plot(PRED_train.numpy(), i, Loss_train.numpy())    loss_buf.append(Loss_train.numpy())plt.figure("损失值")plt.plot(loss_buf, c='b', lw=3)plt.xlim(0, 1000)plt.ylim(0, 0.1)plt.xlabel('epoch', fontsize=10)plt.ylabel('loss', fontsize=10)plt.show()